blocks.body:
{
    "level": "A1–B1",
    "intro": "Почни з <strong>ролей слів</strong>, простої будови речення, підрозділу <strong>Verb to Be</strong> і базового <strong>word order</strong>.",
    "rules": [
        {
            "label": "Parts of Speech",
            "color": "emerald",
            "text": "Спершу зрозумій, яку роль слово має в реченні.",
            "example": "noun, verb, adjective, adverb"
        },
        {
            "label": "Sentence Basics",
            "color": "blue",
            "text": "Потім закріпи просту модель речення і його базові типи.",
            "example": "Subject + Verb + Object"
        },
        {
            "label": "Verb to Be + Word Order",
            "color": "amber",
            "text": "Далі переходь до <strong>Verb to Be</strong> і <strong>Word Order</strong>, щоб будувати природні A1 речення.",
            "example": "I am ready. / Are they here? / She often works at home."
        }
    ]
}

{
    "title": "1. Стартові теми",
    "intro": "Тут зібрані теми, з яких зручно починати граматику на рівні A1–A2.",
    "items": [
        {
            "label": "Parts of Speech",
            "title": "Частини мови",
            "subtitle": "Іменники, дієслова, прикметники, прислівники та інші ролі слів."
        },
        {
            "label": "Sentence Structure",
            "title": "Будова речення",
            "subtitle": "Проста модель речення і базова структура SVO."
        },
        {
            "label": "Sentence Types",
            "title": "Види речень",
            "subtitle": "Ствердження, питання, заперечення і наказові форми."
        },
        {
            "label": "Imperatives",
            "title": "Наказова форма",
            "subtitle": "Короткі команди, прохання та інструкції."
        },
        {
            "label": "Conjunctions",
            "title": "Сполучники",
            "subtitle": "and, but, or, because, so у простих зв'язках."
        },
        {
            "label": "Word Order",
            "title": "Порядок слів",
            "subtitle": "Окремий підрозділ про порядок слів у реченні."
        },
        {
            "label": "Verb to Be",
            "title": "Verb to Be",
            "subtitle": "am, is, are, заперечення, питання і there is / there are."
        }
    ]
}

{
    "title": "2. Зручний маршрут",
    "sections": [
        {
            "label": "Фундамент",
            "color": "emerald",
            "description": "Почни з <strong>Parts of Speech</strong> і <strong>Sentence Structure</strong>, щоб побачити ролі слів і каркас простого речення.",
            "examples": [
                {
                    "en": "The student reads a book.",
                    "ua": "Підмет + дієслово + додаток."
                }
            ]
        },
        {
            "label": "Базові моделі",
            "color": "blue",
            "description": "Далі візьми <strong>Sentence Types</strong>, <strong>Imperatives</strong> і <strong>Conjunctions</strong>, щоб будувати короткі робочі моделі речень.",
            "examples": [
                {
                    "en": "Open the window. / I was tired, so I stayed home.",
                    "ua": "Команди, питання, заперечення і прості зв'язки."
                }
            ]
        },
        {
            "label": "Verb to Be + Word Order",
            "color": "amber",
            "description": "Після цього переходь до <strong>Verb to Be</strong> і <strong>Word Order</strong>, щоб речення звучали природно від самого старту.",
            "examples": [
                {
                    "en": "I am ready. / Are they at school? / She often works at home.",
                    "ua": "Форми to be, прості питання і природний порядок слів."
                }
            ]
        }
    ]
}

{
    "title": "3. Коротко",
    "items": [
        "<strong>Parts of Speech</strong> показує, що саме робить слово в реченні.",
        "<strong>Sentence Structure</strong> і <strong>Sentence Types</strong> дають базові моделі для A1 речень.",
        "<strong>Imperatives</strong> і <strong>Conjunctions</strong> додають команди, прохання та прості зв'язки.",
        "<strong>Word Order</strong> допомагає ставити слова в природному порядку.",
        "<strong>Verb to Be</strong> закриває стартові форми <strong>am / is / are</strong>, питання і <strong>there is / there are</strong>."
    ]
}
